#include <iostream>
#include <string>
#include <unordered_map>
using namespace std;

// 递归构建树并输出后序遍历
void buildTreeAndPostorder(string& inorder, string& preorder, int inStart, int inEnd, int preStart, int preEnd, unordered_map<char, int>& inMap) {
    if (inStart > inEnd || preStart > preEnd) {
        return;
    }

    // 前序遍历的第一个元素是根节点
    char rootVal = preorder[preStart];
    int rootIndex = inMap[rootVal]; // 根节点在中序遍历中的位置

    // 计算左子树的节点数量
    int leftSize = rootIndex - inStart;

    // 递归构建左子树
    buildTreeAndPostorder(inorder, preorder, inStart, rootIndex - 1, preStart + 1, preStart + leftSize, inMap);

    // 递归构建右子树
    buildTreeAndPostorder(inorder, preorder, rootIndex + 1, inEnd, preStart + leftSize + 1, preEnd, inMap);

    // 输出根节点（后序遍历的顺序）
    cout << rootVal;
}

int main() {
    string inorder, preorder;
    cin >> inorder >> preorder;

    // 创建中序遍历的字符到索引的映射
    unordered_map<char, int> inMap;
    for (int i = 0; i < inorder.size(); i++) {
        inMap[inorder[i]] = i;
    }

    // 调用递归函数构建树并输出后序遍历
    buildTreeAndPostorder(inorder, preorder, 0, inorder.size() - 1, 0, preorder.size() - 1, inMap);

    cout << endl;
    return 0;
}
